#include "headless_python_executor.h"
#include "python_exec_thread.h"

#include <wx/log.h>
#include <wx/utils.h>
#include <wx/txtstrm.h>
#include <wx/filename.h>
#include <python_scripting.h>
#include <api/api_handler_editor.h>

#ifndef _WIN32
#include <signal.h>
#include <unistd.h>
#endif


HEADLESS_PYTHON_EXECUTOR::HEADLESS_PYTHON_EXECUTOR() :
        m_pythonThread( nullptr ),
        m_pythonRunning( false ),
        m_childProcessPid( 0 ),
        m_pythonCancelled( false ),
        m_pythonTimedOut( false ),
        m_pythonInitialized( false ),
        m_process( nullptr ),
        m_shellStdin( nullptr ),
        m_shellStdout( nullptr ),
        m_shellStderr( nullptr ),
        m_pid( -1 )
{
    m_pythonPollTimer.SetOwner( this );

    Bind( wxEVT_PYTHON_COMPLETE, &HEADLESS_PYTHON_EXECUTOR::OnPythonComplete, this );
    Bind( wxEVT_TIMER, &HEADLESS_PYTHON_EXECUTOR::OnPythonPollTimer, this,
          m_pythonPollTimer.GetId() );
}


HEADLESS_PYTHON_EXECUTOR::~HEADLESS_PYTHON_EXECUTOR()
{
    m_pythonPollTimer.Stop();

    if( m_pythonThread )
    {
        m_pythonThread->RequestStop();
        m_pythonThread->Wait();
        delete m_pythonThread;
        m_pythonThread = nullptr;
    }

    CleanupShell();
}


void HEADLESS_PYTHON_EXECUTOR::CancelExecution()
{
    if( !m_pythonRunning.load() )
    {
        wxLogInfo( "HEADLESS_EXEC: CancelExecution called but nothing running — no-op" );
        return;
    }

    wxLogInfo( "HEADLESS_EXEC: CancelExecution — interrupting in-flight Python execution" );

    // Step 1: Kill any tracked external child process (e.g., Freerouting Java)
    pid_t childPid = m_childProcessPid.load();
    if( childPid > 0 )
    {
        wxLogInfo( "HEADLESS_EXEC: Killing child process PID %d", (int) childPid );
#ifndef _WIN32
        kill( childPid, SIGTERM );

        // Give it a moment to exit gracefully, then force-kill
        usleep( 200000 );  // 200ms

        if( kill( childPid, 0 ) == 0 )  // Still alive?
        {
            wxLogInfo( "HEADLESS_EXEC: Child PID %d still alive, sending SIGKILL", (int) childPid );
            kill( childPid, SIGKILL );
        }
#else
        // On Windows, TerminateProcess would be used — not yet implemented
#endif
        m_childProcessPid.store( 0 );
    }

    // Step 2: Signal the Python thread to stop
    if( m_pythonThread )
        m_pythonThread->InterruptPython();

    // Step 3: Force-complete the execution state immediately.
    // We can't block waiting for the Python thread (it may be in a C extension
    // IPC call that needs the main thread to respond — deadlock). Instead, we
    // mark execution as done so the poll timer triggers FinishPythonExecution
    // on the next tick and the agent can proceed.
    // The Python thread will finish on its own in the background; its
    // m_stopRequested flag prevents it from posting the completion event.
    wxLogInfo( "HEADLESS_EXEC: CancelExecution — force-marking execution as done" );
    m_lastPythonResult = "Cancelled";
    m_pythonRunning.store( false );
    m_pythonCancelled = true;
    m_pythonTimedOut = true;
}


bool HEADLESS_PYTHON_EXECUTOR::EnsurePython()
{
#ifdef KICAD_SCRIPTING
    if( m_pythonInitialized )
        return true;

/*
 * Copyright (C) 2026, Zeo <team@zeo.dev>
 */

#ifndef PYTHON_EXEC_THREAD_H
#define PYTHON_EXEC_THREAD_H

#include <wx/thread.h>
#include <wx/event.h>
#include <string>
#include <atomic>
#include <Python.h>

// Custom events for Python execution
wxDECLARE_EVENT( wxEVT_PYTHON_OUTPUT, wxThreadEvent );
wxDECLARE_EVENT( wxEVT_PYTHON_COMPLETE, wxThreadEvent );

/**
 * Background thread for executing Python code.
 *
 * This thread allows Python code to run without blocking the main wx event loop,
 * which is critical for IPC shell operations that call back into the KiCad API.
 * The API server processes requests via wx events, so the event loop must remain
 * responsive during Python execution.
 */
class PYTHON_EXEC_THREAD : public wxThread
{
public:
    /**
     * Create a new Python execution thread.
     *
     * @param aHandler Event handler to receive output and completion events
     * @param aCode Python code to execute
     */
    PYTHON_EXEC_THREAD( wxEvtHandler* aHandler, const std::string& aCode );

    virtual ~PYTHON_EXEC_THREAD();

    /**
     * Thread entry point - executes the Python code.
     */
    virtual void* Entry() override;

    /**
     * Request the thread to stop execution.
     */
    void RequestStop() { m_stopRequested.store( true ); }

    /**
     * Get the Python thread identifier (set after GIL acquisition in Entry()).
     * Returns 0 if the thread hasn't started or hasn't acquired the GIL yet.
     */
    unsigned long GetPythonThreadId() const { return m_pythonThreadId.load(); }

    /**
     * Raise an asynchronous exception in the running Python code.
     * Uses PyThreadState_SetAsyncExc to inject KeyboardInterrupt at the next
     * bytecode instruction boundary. Returns true if the exception was set.
     */
    bool InterruptPython();

private:
    wxEvtHandler*              m_handler;
    std::string                m_code;
    std::atomic<bool>          m_stopRequested;
    std::atomic<unsigned long> m_pythonThreadId;
};

#endif // PYTHON_EXEC_THREAD_H

