                                  | wxEVT_CATEGORY_THREAD
                                  | wxEVT_CATEGORY_SOCKET
                                  | wxEVT_CATEGORY_UI
                                  | wxEVT_CATEGORY_UNKNOWN;

while( m_toolResponse == NO_RESPONSE_SENTINEL && ( wxGetLocalTimeMillis() - start < TIMEOUT_MS ) )
{
