    {
        wxLogInfo( "AGENT: SendRequest cancelled by user after %lld ms",
                   ( wxGetLocalTimeMillis() - start ).GetValue() );
        return "Error: Tool execution cancelled by user.";
    }
    wxMilliSleep( 10 );
}

