        WARNING_ICON      = 0x04,
        LABEL_BUTTON      = 0x08,
    };

    static constexpr auto DEFAULT_STYLE =
            static_cast<STYLE_FLAGS>( NOTIFICATION_ICON | CANCEL_BUTTON );

